class Solution {
public:
    long long smallestNumber(long long num) {
        if (num == 0) return 0;
        bool negative = false;
        if (num < 0) {
            num = -num;
            negative = true;
        }
        vector<int> digits;
        while (num > 0) {
            digits.push_back(num % 10);
            num /= 10;
        }
        sort(digits.begin(), digits.end());
        if (negative) digits[0] = -digits[0];
        for (int i = 0; i < digits.size(); i++) {
            if (digits[i] == 0 && i == 0) continue;
            if (negative && digits[i] == 0) {
                for (int j = i; j < digits.size() - 1; j++) {
                    digits[j] = digits[j + 1];
                }
                digits.pop_back();
                break;
            }
            if (negative && digits[i] < 0) {
                for (int j = i; j < digits.size() - 1; j++) {
                    digits[j] = digits[j + 1];
                }
                digits.pop_back();
                break;
            }
            if (negative) digits[i] = -digits[i];
            if (i == 0 && digits[i] == 0) digits[i] = 1;
            num = num * 10 + digits[i];
        }
        return num;
    }
};
